import{_ as a,o,c as t,a3 as i}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"56. Daylight Savings","description":"","frontmatter":{"title":"56. Daylight Savings","eba":"Allied Health Professionals 2021-2026","topics":["hours","overtime","shift-work","rosters"]},"headers":[],"relativePath":"ebas/allied-health/hours-of-work/56-daylight-savings.md","filePath":"ebas/allied-health/hours-of-work/56-daylight-savings.md"}'),s={name:"ebas/allied-health/hours-of-work/56-daylight-savings.md"};function r(n,e,l,h,d,c){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="_56-daylight-savings" tabindex="-1">56. Daylight Savings <a class="header-anchor" href="#_56-daylight-savings" aria-label="Permalink to &quot;56. Daylight Savings&quot;">​</a></h1><p>See also <a href="/eba/ebas/allied-health/hours-of-work/52-overtime.html">clauses 52</a> (Overtime) and 48 (Accrued Days Off).</p><p><strong>56.1</strong> Despite the overtime provisions of this Agreement, if an Employee works on a shift during which time changes because of the introduction of, or cessation to, daylight saving, that Employee will be paid for the actual hours worked at the applicable ordinary time rate of pay (including any applicable shift allowances, allowances ordinarily payable in respect of the shift and special rates for Saturdays and Sundays). Examples:</p><ol><li>An Employee is rostered to work an eight (8) hour night shift from 11pm through to 7am (including a paid 30 minute meal break). During the course of this shift, the clock is wound forward one (1) hour due to the commencement of daylight saving.</li></ol><p>The Employee therefore works seven (7) hours. The Employee is paid seven (7) hours at the applicable ordinary time rate of pay (including any shift allowances, allowances ordinarily payable in respect of this shift and special rates for Saturdays and Sundays).</p><ol><li>An Employee is rostered to work a ten hour night shift from 9pm through to 7am (including a paid 30 minute meal break). During the course of this shift, the clock is wound back one (1) hour due to the cessation of daylight saving.</li></ol><p>The Employee therefore works 11 hours. The Employee is paid 11 hours at the applicable ordinary time rate of pay (including any shift allowances, allowances ordinarily payable in respect of this shift and special rates for</p><p>Saturdays and Sundays). No overtime is paid for the additional hour worked.</p><p><strong>56.2</strong> For the purpose of calculating accrued days off, Employees who work on a shift during which time changes because of the introduction of, or cessation to, daylight saving, will be taken to have worked the standard hours for a night shift in accordance with the roster.</p><p>Plain language terms: saved conditions.</p>',10)])])}const u=a(s,[["render",r]]);export{f as __pageData,u as default};
